void test_CB_E6_0000()
{
    if (skip_test_CB_E6_0000)
    {
        TEST_SKIP("Skipping");
        return;
    }
    mmap.Reset();
    auto mmapResult = mmap.Initialize(MinRomBankCount, MinVramBankCount, 1, MinWramBankCount);
    TEST_ASSERT_(mmapResult.IsSuccess(), "%s", mmapResult.GetStatusDescription());

    // Initial state

    WriteRegisterWord(RegisterType::PC, 0x59FF);
    WriteRegisterWord(RegisterType::SP, 0x6B36);
    WriteRegisterByte(RegisterType::A, 0x33);
    WriteRegisterByte(RegisterType::B, 0x40);
    WriteRegisterByte(RegisterType::C, 0x94);
    WriteRegisterByte(RegisterType::D, 0xE2);
    WriteRegisterByte(RegisterType::E, 0x85);
    WriteRegisterFlag(0x30);
    WriteRegisterByte(RegisterType::H, 0x31);
    WriteRegisterByte(RegisterType::L, 0xA2);
    mmap.EnableIME();
    WriteRegisterByte(RegisterType::IE, 0x00);
    WriteMemory(0x5A00, 0xE6);
    WriteMemory(0x59FF, 0xCB);
    WriteMemory(0x31A2, 0x75);

    // Execute step
    {
        auto resultByte = mmap.ReadByte(mmap.ReadPC());
        TEST_ASSERT_(resultByte.IsSuccess(), "%s", resultByte.GetStatusDescription());
        auto ticks = ExecuteActiveDecoder(static_cast<const Byte&>(resultByte), mmap);
        TEST_ASSERT(ticks == GetInstructionTicks(static_cast<const Byte&>(resultByte), 0x00));

        // Execute additional step for prefix
        auto resultByte2 = mmap.ReadByte(mmap.ReadPC());
        TEST_ASSERT_(resultByte2.IsSuccess(), "%s", resultByte2.GetStatusDescription());
        auto ticks2 = ExecuteActiveDecoder(static_cast<const Byte&>(resultByte2), mmap);
        TEST_ASSERT(ticks2 == GetInstructionTicks(static_cast<const Byte&>(resultByte2), 0xCB));
        TEST_ASSERT(ticks + ticks2 == 16);
    }

    // Final state
            
    CheckRegisterByte(RegisterType::A, 0x33);
    CheckRegisterByte(RegisterType::B, 0x40);
    CheckRegisterByte(RegisterType::C, 0x94);
    CheckRegisterByte(RegisterType::D, 0xE2);
    CheckRegisterByte(RegisterType::E, 0x85);
    CheckRegisterFlag(0x30);
    CheckRegisterByte(RegisterType::H, 0x31);
    CheckRegisterByte(RegisterType::L, 0xA2);
    CheckRegisterWord(RegisterType::PC, 0x5A01);
    CheckRegisterWord(RegisterType::SP, 0x6B36);
    TEST_ASSERT(mmap.IMEEnabled());
    CheckMemory(0x31A2, 0x75);
    CheckMemory(0x59FF, 0xCB);
    CheckMemory(0x5A00, 0xE6);
}

